  WITH CHECK (EXISTS (SELECT 1 FROM tasks tk JOIN projects pr ON pr.id = tk.project_id JOIN property_definitions pd ON pd.id = task_property_values.property_id WHERE tk.id = task_property_values.task_id AND pr.initiative_id = pd.initiative_id AND public.initiative_access(pd.initiative_id, (NULLIF(current_setting('app.current_user_id'::text, true), ''::text))::integer, true)));
DROP POLICY IF EXISTS initiative_member_update ON task_property_values;
CREATE POLICY initiative_member_update ON task_property_values AS PERMISSIVE FOR UPDATE
  USING (EXISTS (SELECT 1 FROM tasks tk JOIN projects pr ON pr.id = tk.project_id JOIN property_definitions pd ON pd.id = task_property_values.property_id WHERE tk.id = task_property_values.task_id AND pr.initiative_id = pd.initiative_id AND public.initiative_access(pd.initiative_id, (NULLIF(current_setting('app.current_user_id'::text, true), ''::text))::integer, true))) WITH CHECK (EXISTS (SELECT 1 FROM tasks tk JOIN projects pr ON pr.id = tk.project_id JOIN property_definitions pd ON pd.id = task_property_values.property_id WHERE tk.id = task_property_values.task_id AND pr.initiative_id = pd.initiative_id AND public.initiative_access(pd.initiative_id, (NULLIF(current_setting('app.current_user_id'::text, true), ''::text))::integer, true)));
DROP POLICY IF EXISTS initiative_member_delete ON task_property_values;
CREATE POLICY initiative_member_delete ON task_property_values AS PERMISSIVE FOR DELETE
  USING (EXISTS (SELECT 1 FROM tasks tk JOIN projects pr ON pr.id = tk.project_id JOIN property_definitions pd ON pd.id = task_property_values.property_id WHERE tk.id = task_property_values.task_id AND pr.initiative_id = pd.initiative_id AND public.initiative_access(pd.initiative_id, (NULLIF(current_setting('app.current_user_id'::text, true), ''::text))::integer, true)));

